#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,a,w=0,sum=0;
    cin>>n;
    while(cin>>a){
        for(int i=1;i<=a;i++){
            if(sum==n){
				cout<<endl;
				sum=0;
			}
            sum++;
            cout<<w;
        }
        if(w==0)w=1;
        else w=0;
    }
    return 0;
}
